		"disk quota exceeded",
		"temp root is full",
		"cannot allocate memory"):
		return ReadinessSystemReasonResourceExhausted
	case containsAny(combined, "worktree") && containsAny(combined,
		"failed",
		"lost",
		"missing",
		"cannot",
		"no such file",
		"not found",
		"no space"):
