// claimCountingStore wraps bead.Store and counts Claim invocations. The rest
// of ExecuteBeadLoopStore is delegated to the embedded *bead.Store.
type claimCountingStore struct {
	*bead.Store
	claimCalls  int32
	beforeClaim func()
